  ('dietitian-moex-08914', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '近年國民營養調查數據顯示，兒童、青少年和成人肥胖日漸增加，目前行政院衛生署訂定「成人肥胖定 義及處理原則」乃使用身體質量指數和下列何項指標作為篩選？', '["腰圍", "體脂肪", "腰臀比", "皮脂厚度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
